{
  "name": "Nano Banana AI Studio",
  "description": "A professional AI image generation tool using the Nano Banana API with support for multiple models, reference images, and concurrent generation."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum TaskStatus {
  PENDING = 'pending',
  RUNNING = 'running',
  SUCCEEDED = 'succeeded',
  FAILED = 'failed',
}

export interface GenerationTask {
  id: string; // Internal UUID or API ID
  apiTaskId?: string; // ID returned by API
  status: TaskStatus;
  prompt: string;
  model: string;
  createdAt: number;
  resultUrl?: string;
  error?: string;
  progress: number;
}

export interface GenerationConfig {
  model: string;
  prompt: string;
  aspectRatio: string;
  imageSize: string;
  refImages: string[]; // Base64 strings
}

export interface ApiCreateResponse {
  code: number;
  msg: string;
  data: {
    id: string;
  };
}

export interface ApiResultResponse {
  code: number;
  msg: string;
  data: {
    id: string;
    results: Array<{ url: string; content: string }>;
    progress: number;
    status: string; // running, succeeded, failed
    failure_reason?: string;
    error?: string;
  };
}

export const MODELS = [
  { value: 'nano-banana-fast', label: 'Nano Banana Fast' },
  { value: 'nano-banana', label: 'Nano Banana' },
  { value: 'nano-banana-pro', label: 'Nano Banana Pro' },
  { value: 'nano-banana-pro-vt', label: 'Nano Banana Pro VT' },
  { value: 'nano-banana-pro-cl', label: 'Nano Banana Pro CL' },
  { value: 'nano-banana-pro-vip', label: 'Nano Banana Pro VIP' },
  { value: 'nano-banana-pro-4k-vip', label: 'Nano Banana Pro 4K VIP' },
];

export const ASPECT_RATIOS = [
  { value: 'auto', label: 'Auto' },
  { value: '1:1', label: '1:1 (Square)' },
  { value: '16:9', label: '16:9 (Landscape)' },
  { value: '9:16', label: '9:16 (Portrait)' },
  { value: '4:3', label: '4:3' },
  { value: '3:4', label: '3:4' },
  { value: '3:2', label: '3:2' },
  { value: '2:3', label: '2:3' },
  { value: '21:9', label: '21:9 (Ultrawide)' },
];

export const IMAGE_SIZES = [
  { value: '1K', label: '1K' },
  { value: '2K', label: '2K (Pro VIP only)' },
  { value: '4K', label: '4K (Pro 4K only)' },
];

import { ApiCreateResponse, ApiResultResponse, GenerationConfig } from '../types';

const API_BASE_URL = 'https://grsai.dakka.com.cn/v1/draw';

export const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result as string);
    reader.onerror = (error) => reject(error);
  });
};

export const createGenerationTask = async (apiKey: string, config: GenerationConfig): Promise<string> => {
  const payload = {
    model: config.model,
    prompt: config.prompt,
    aspectRatio: config.aspectRatio,
    imageSize: config.imageSize,
    urls: config.refImages.length > 0 ? config.refImages : undefined,
    webHook: "-1", // Polling mode
    shutProgress: false,
  };

  const response = await fetch(`${API_BASE_URL}/nano-banana`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${apiKey}`,
    },
    body: JSON.stringify(payload),
  });

  if (!response.ok) {
    const errText = await response.text();
    throw new Error(`API Error ${response.status}: ${errText}`);
  }

  const data: ApiCreateResponse = await response.json();
  if (data.code !== 0) {
    throw new Error(data.msg || 'Unknown API error');
  }

  return data.data.id;
};

export const fetchTaskResult = async (apiKey: string, taskId: string): Promise<ApiResultResponse['data']> => {
  const response = await fetch(`${API_BASE_URL}/result`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${apiKey}`,
    },
    body: JSON.stringify({ id: taskId }),
  });

  if (!response.ok) {
    throw new Error('Failed to check task status');
  }

  const data: ApiResultResponse = await response.json();
  // Note: The API might return code -22 if task not found, handle gracefully in UI if needed
  if (data.code !== 0 && data.code !== 200) { 
       // Sometimes APIs return 200 in code for success, or 0.
       // Based on docs: 0 = success.
       throw new Error(data.msg);
  }

  return data.data;
};

import React, { useState, useEffect } from 'react';
