import React, { useState, useEffect, useRef } from 'react';
import { X, Plus, Trash2, User, ImagePlus, Save } from 'lucide-react';
import { Character } from '../types';
import { fileToBase64 } from '../services/api';

interface CharacterLibraryModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSelect: (character: Character) => void;
}

export const CharacterLibraryModal: React.FC<CharacterLibraryModalProps> = ({ isOpen, onClose, onSelect }) => {
  const [characters, setCharacters] = useState<Character[]>(() => {
    const saved = localStorage.getItem('grsai_character_library');
    return saved ? JSON.parse(saved) : [];
  });

  const [isAdding, setIsAdding] = useState(false);
  const [newName, setNewName] = useState('');
  const [newCode, setNewCode] = useState('');
  const [newImage, setNewImage] = useState<string>('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    localStorage.setItem('grsai_character_library', JSON.stringify(characters));
  }, [characters]);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      try {
        const base64 = await fileToBase64(e.target.files[0]);
        setNewImage(base64);
      } catch (err) {
        console.error(err);
      }
    }
  };

  const handleAddCharacter = () => {
    if (!newName || !newCode || !newImage) {
      alert("请填写完整信息：名称、代码和图片");
      return;
    }
    const newChar: Character = {
      id: crypto.randomUUID(),
      name: newName,
      code: newCode,
      image: newImage
    };
    setCharacters(prev => [...prev, newChar]);
    setIsAdding(false);
    setNewName('');
    setNewCode('');
    setNewImage('');
  };

  const handleDelete = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('确定要删除这个角色吗？')) {
      setCharacters(prev => prev.filter(c => c.id !== id));
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm">
      <div className="bg-[#1e293b] border border-slate-700 rounded-xl shadow-2xl w-full max-w-4xl max-h-[85vh] flex flex-col overflow-hidden">

        {/* Header */}
        <div className="p-4 border-b border-slate-700 flex justify-between items-center bg-[#0f172a]">
          <div className="flex items-center gap-2">
            <User className="text-blue-400" size={24} />
            <h2 className="text-xl font-bold text-white">角色参考库</h2>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-700 rounded-full text-slate-400 hover:text-white transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 bg-[#1e293b]">

          {/* Add Form or Button */}
          {isAdding ? (
            <div className="mb-6 p-4 bg-[#0f172a] rounded-lg border border-slate-600 animate-in fade-in slide-in-from-top-4">
               <h3 className="text-sm font-bold text-slate-300 mb-4 uppercase tracking-wider">添加新角色</h3>
               <div className="flex gap-4 items-start">
                  <div 
                    onClick={() => fileInputRef.current?.click()}
                    className="w-24 h-24 flex-shrink-0 border-2 border-dashed border-slate-600 rounded-lg hover:border-blue-500 hover:bg-slate-800 cursor-pointer flex flex-col items-center justify-center transition-colors relative overflow-hidden"
                  >
                     {newImage ? (
                       <img src={newImage} alt="Preview" className="w-full h-full object-cover" />
                     ) : (
                       <>
                         <ImagePlus className="text-slate-500 mb-1" />
                         <span className="text-[10px] text-slate-500">上传图片</span>
                       </>
                     )}
                     <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
                  </div>

                  <div className="flex-1 space-y-3">
                    <div>
                      <input 
                        type="text" 
                        placeholder="角色名称 (如: 赛博少女)" 
                        value={newName}
                        onChange={e => setNewName(e.target.value)}
                        className="w-full bg-[#1e293b] border border-slate-700 text-white text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 p-2.5"
                      />
                    </div>
                    <div>
                      <input 
                        type="text" 
                        placeholder="角色代码 (如: @shjieai3.kzsip)" 
                        value={newCode}
                        onChange={e => setNewCode(e.target.value)}
                        className="w-full bg-[#1e293b] border border-slate-700 text-white text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 p-2.5 font-mono"
                      />
                    </div>
                  </div>
               </div>
               <div className="flex justify-end gap-2 mt-4">
                 <button onClick={() => setIsAdding(false)} className="px-3 py-1.5 text-xs text-slate-400 hover:text-white">取消</button>
                 <button onClick={handleAddCharacter} className="px-3 py-1.5 text-xs bg-blue-600 text-white rounded hover:bg-blue-500 flex items-center gap-1">
                   <Save size={14} /> 保存角色
                 </button>
               </div>
            </div>
          ) : (
            <button 
              onClick={() => setIsAdding(true)}
              className="w-full mb-6 py-3 border-2 border-dashed border-slate-700 rounded-lg text-slate-400 hover:text-blue-400 hover:border-blue-500/50 hover:bg-slate-800/50 transition-all flex items-center justify-center gap-2 font-medium"
            >
              <Plus size={20} /> 添加新角色
            </button>
          )}

          {/* Grid */}
          {characters.length === 0 && !isAdding ? (
            <div className="text-center py-12 text-slate-500">
              <User size={48} className="mx-auto mb-3 opacity-20" />
              <p>暂无角色，请点击上方添加</p>
            </div>
          ) : (
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
              {characters.map((char) => (
                <div 
                  key={char.id} 
                  onClick={() => onSelect(char)}
                  className="group relative bg-[#0f172a] rounded-lg border border-slate-700 overflow-hidden cursor-pointer hover:ring-2 hover:ring-blue-500 hover:border-transparent transition-all"
                >
                   <div className="aspect-square relative">
                      <img src={char.image} alt={char.name} className="w-full h-full object-cover" />
                      <div className="absolute inset-0 bg-black/0 group-hover:bg-black/20 transition-colors" />
                   </div>
                   <div className="p-3">
                      <div className="font-bold text-white text-sm truncate">{char.name}</div>
                      <div className="text-xs text-slate-400 font-mono truncate mt-1 bg-[#1e293b] p-1 rounded">
                        {char.code}
                      </div>
                   </div>

                   <button 
                     onClick={(e) => handleDelete(char.id, e)}
                     className="absolute top-2 right-2 p-1.5 bg-red-500/80 text-white rounded opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-600"
                     title="删除"
                   >
                     <Trash2 size={14} />
                   </button>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="p-4 border-t border-slate-700 bg-[#0f172a] text-xs text-slate-400 flex justify-between items-center">
            <span>点击卡片即可将角色添加到参考图，并自动插入提示词。</span>
            <span>{characters.length} 个角色</span>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Settings, Image as ImageIcon, Trash2, Maximize2, Loader2, Plus, X, RefreshCw, Eraser, BookUser } from 'lucide-react';
import { GenerationTask, TaskStatus, MODELS, ASPECT_RATIOS, IMAGE_SIZES, Character } from './types';
import { createGenerationTask, fetchTaskResult, fileToBase64 } from './services/api';
import { ApiKeyModal } from './components/ApiKeyModal';
import { Lightbox } from './components/Lightbox';
import { CharacterLibraryModal } from './components/CharacterLibraryModal';

const App: React.FC = () => {
  // --- State ---
  const [apiKey, setApiKey] = useState<string>(() => localStorage.getItem('grsai_api_key') || '');
  const [isKeyModalOpen, setKeyModalOpen] = useState(false);
  const [isLibraryOpen, setLibraryOpen] = useState(false);

  // Form State
  const [model, setModel] = useState(MODELS[1].value); // Default to regular nano-banana
  const [aspectRatio, setAspectRatio] = useState('1:1');
  const [imageSize, setImageSize] = useState('1K');
  const [prompt, setPrompt] = useState('');
  const [refImages, setRefImages] = useState<string[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Replacement State
  const replaceFileRef = useRef<HTMLInputElement>(null);
  const [replacingIndex, setReplacingIndex] = useState<number | null>(null);

  // Tasks State
  const [tasks, setTasks] = useState<GenerationTask[]>([]);
  const [selectedImage, setSelectedImage] = useState<string | null>(null);

  // --- Helpers ---
  const handleSaveKey = (key: string) => {
    setApiKey(key);
    localStorage.setItem('grsai_api_key', key);
    setKeyModalOpen(false);
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newImages: string[] = [];
      const files = Array.from(e.target.files);

      // Limit total to 10
      const remainingSlots = 10 - refImages.length;
      const filesToProcess = files.slice(0, remainingSlots);

      for (const file of filesToProcess) {
        try {
          const base64 = await fileToBase64(file);
          newImages.push(base64);
        } catch (err) {
          console.error("Error reading file", err);
        }
      }
      setRefImages(prev => [...prev, ...newImages]);
    }
    // Reset input
    e.target.value = '';
  };

  const handleSelectCharacter = (character: Character) => {
    if (refImages.length >= 10) {
      alert("参考图数量已达上限 (10张)，请先删除一些图片。");
      return;
    }

    // 1. Add Image
    setRefImages(prev => [...prev, character.image]);

    // 2. Prepend Prompt
    const refIndex = refImages.length + 1; // 1-based index for the new image
    const triggerText = `参考图${refIndex}是${character.code}，`;

    setPrompt(prev => triggerText + prev);

    // Close modal
    setLibraryOpen(false);
  };

  const handleReplaceClick = (index: number) => {
    setReplacingIndex(index);
    replaceFileRef.current?.click();
  };

  const handleReplaceFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0] && replacingIndex !== null) {
      try {
        const base64 = await fileToBase64(e.target.files[0]);
        setRefImages(prev => {
          const newArr = [...prev];
          newArr[replacingIndex] = base64;
          return newArr;
        });
      } catch (err) {
        console.error("Error replacing file", err);
      }
    }
    // Reset
    if (replaceFileRef.current) replaceFileRef.current.value = '';
    setReplacingIndex(null);
  };

  const removeRefImage = (index: number) => {
    setRefImages(prev => prev.filter((_, i) => i !== index));
  };

  const handleDeleteTask = (taskId: string) => {
    setTasks(prev => prev.filter(t => t.id !== taskId));
  };

  // --- API Interaction ---
  const handleGenerate = async () => {
    if (!apiKey) {
      setKeyModalOpen(true);
      return;
    }
    if (!prompt.trim()) {
      alert("请输入提示词描述 (Prompt)");
      return;
    }

    setIsSubmitting(true);
    const tempId = crypto.randomUUID();

    // Create a local placeholder task
    const newTask: GenerationTask = {
      id: tempId,
      status: TaskStatus.PENDING,
      prompt: prompt,
      model: model,
      createdAt: Date.now(),
      progress: 0,
    };

    setTasks(prev => [newTask, ...prev]);

    try {
      const apiId = await createGenerationTask(apiKey, {
        model,
        prompt,
        aspectRatio,
        imageSize,
        refImages,
      });

      // Update task with real API ID and set to running
      setTasks(prev => prev.map(t => 
        t.id === tempId ? { ...t, apiTaskId: apiId, status: TaskStatus.RUNNING } : t
      ));

    } catch (error: any) {
      setTasks(prev => prev.map(t => 
        t.id === tempId ? { ...t, status: TaskStatus.FAILED, error: error.message } : t
      ));
    } finally {
      setIsSubmitting(false);
    }
  };

  // --- Polling Logic ---
  useEffect(() => {
    const intervalId = setInterval(async () => {
      // Find tasks that are running and have an API ID
      const runningTasks = tasks.filter(t => t.status === TaskStatus.RUNNING && t.apiTaskId);

      if (runningTasks.length === 0) return;

      for (const task of runningTasks) {
        try {
          if (!apiKey || !task.apiTaskId) continue;

          const result = await fetchTaskResult(apiKey, task.apiTaskId);

          if (result.status === 'succeeded') {
            setTasks(prev => prev.map(t => 
              t.id === task.id ? {
                ...t,
                status: TaskStatus.SUCCEEDED,
                progress: 100,
                resultUrl: result.results[0]?.url
              } : t
            ));
          } else if (result.status === 'failed') {
             setTasks(prev => prev.map(t => 
              t.id === task.id ? {
                ...t,
                status: TaskStatus.FAILED,
                error: result.failure_reason || result.error || 'Unknown error'
              } : t
            ));
          } else {
            // Still running, update progress if available
             setTasks(prev => prev.map(t => 
              t.id === task.id ? {
                ...t,
                progress: result.progress || t.progress
              } : t
            ));
          }

        } catch (error) {
          console.error(`Error polling task ${task.id}`, error);
          // Optional: Mark as failed if polling fails repeatedly, but for now just ignore
        }
      }
    }, 3000); // Check every 3 seconds

    return () => clearInterval(intervalId);
  }, [tasks, apiKey]);


  return (
    <div className="flex h-screen bg-[#020617] font-sans selection:bg-blue-500/30">

      {/* Left Sidebar - Controls */}
      <div className="w-[400px] flex-shrink-0 bg-[#0f172a] border-r border-slate-800 flex flex-col h-full overflow-y-auto custom-scrollbar">

        {/* Header */}
        <div className="p-6 border-b border-slate-800 flex items-center gap-3 bg-[#0f172a] sticky top-0 z-10">
          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center font-bold text-white">
            JZ
          </div>
          <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-400">
            Nano Banana AI
          </h1>
        </div>

        <div className="p-6 space-y-6 flex-1">
          {/* Tabs - Visual Only for now */}
          <div className="flex p-1 bg-slate-900 rounded-lg border border-slate-800">
             <button className="flex-1 py-2 px-4 text-sm font-medium bg-blue-600 text-white rounded-md shadow-sm transition-all">
               文生图
             </button>
             <button className="flex-1 py-2 px-4 text-sm font-medium text-slate-400 hover:text-white transition-all">
               多图参考
             </button>
          </div>

          {/* Model Selection */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-300">模型选择</label>
            <select 
              value={model}
              onChange={(e) => setModel(e.target.value)}
              className="w-full bg-[#1e293b] border border-slate-700 text-white text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-3 hover:border-slate-600 transition-colors"
            >
              {MODELS.map(m => <option key={m.value} value={m.value}>{m.label}</option>)}
            </select>
          </div>

          {/* Quality and Ratio Row */}
          <div className="grid grid-cols-2 gap-4">
             <div className="space-y-2">
                <label className="text-sm font-medium text-slate-300">画质</label>
                <select 
                  value={imageSize}
                  onChange={(e) => setImageSize(e.target.value)}
                  className="w-full bg-[#1e293b] border border-slate-700 text-white text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-3"
                >
                  {IMAGE_SIZES.map(s => <option key={s.value} value={s.value}>{s.label}</option>)}
                </select>
             </div>
             <div className="space-y-2">
                <label className="text-sm font-medium text-slate-300">比例</label>
                <select 
                  value={aspectRatio}
                  onChange={(e) => setAspectRatio(e.target.value)}
                  className="w-full bg-[#1e293b] border border-slate-700 text-white text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-3"
                >
                  {ASPECT_RATIOS.map(r => <option key={r.value} value={r.value}>{r.label}</option>)}
                </select>
             </div>
          </div>

          {/* Reference Images */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-300 flex justify-between">
              <span>参考图片 (最多10张)</span>
              <span className="text-slate-500">{refImages.length}/10</span>
            </label>

            <input 
              type="file" 
              ref={replaceFileRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleReplaceFileChange} 
            />

            <div className="grid grid-cols-3 gap-2 mb-2">
              {refImages.map((img, idx) => (
                <div key={idx} className="relative group aspect-square rounded-lg overflow-hidden border border-slate-700">
                  <img src={img} alt={`ref-${idx}`} className="w-full h-full object-cover" />
                  <div className="absolute inset-0 bg-black/60 flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button 
                      onClick={() => handleReplaceClick(idx)}
                      className="p-1.5 text-slate-200 hover:text-blue-400 hover:bg-white/10 rounded transition-colors"
                      title="替换图片"
                    >
                      <RefreshCw size={16} />
                    </button>
                    <button 
                      onClick={() => removeRefImage(idx)}
                      className="p-1.5 text-slate-200 hover:text-red-400 hover:bg-white/10 rounded transition-colors"
                      title="删除图片"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                   {/* Index Badge */}
                   <div className="absolute top-1 left-1 bg-black/50 backdrop-blur-sm px-1.5 py-0.5 rounded text-[10px] text-white font-mono">
                     #{idx + 1}
                   </div>
                </div>
              ))}

              {refImages.length < 10 && (
                <>
                <label className="aspect-square border-2 border-dashed border-slate-700 rounded-lg flex flex-col items-center justify-center cursor-pointer hover:border-blue-500 hover:bg-slate-800/50 transition-colors">
                  <Plus className="text-slate-500 mb-1" />
                  <span className="text-xs text-slate-500">上传</span>
                  <input type="file" className="hidden" accept="image/*" multiple onChange={handleFileUpload} />
                </label>

                <button 
                  onClick={() => setLibraryOpen(true)}
                  className="aspect-square border-2 border-dashed border-slate-700 rounded-lg flex flex-col items-center justify-center cursor-pointer hover:border-purple-500 hover:bg-slate-800/50 transition-colors group"
                >
                  <BookUser className="text-slate-500 group-hover:text-purple-400 mb-1" />
                  <span className="text-xs text-slate-500 group-hover:text-purple-400">角色库</span>
                </button>
                </>
              )}
            </div>
          </div>

          {/* Prompt */}
          <div className="space-y-2 flex-1 flex flex-col">
            <label className="text-sm font-medium text-slate-300 flex justify-between items-center">
              <span>提示词 (Prompt)</span>
              <button 
                onClick={() => setPrompt('')}
                className="text-xs text-slate-400 hover:text-red-400 transition-colors flex items-center gap-1 px-2 py-1 rounded hover:bg-slate-800"
                title="清空提示词"
              >
                <Eraser size={12} />
                <span>清空</span>
              </button>
            </label>
            <textarea 
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="请描述你想生成的图片内容..."
              className="w-full flex-1 min-h-[120px] bg-[#1e293b] border border-slate-700 text-white text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-3 resize-none"
            />
          </div>

        </div>

        {/* Generate Button Footer */}
        <div className="p-6 border-t border-slate-800 bg-[#0f172a] sticky bottom-0">
          <button 
            onClick={handleGenerate}
            disabled={isSubmitting}
            className="w-full py-3.5 px-4 bg-gradient-to-r from-pink-600 to-rose-600 hover:from-pink-500 hover:to-rose-500 text-white font-bold rounded-lg shadow-lg shadow-rose-900/20 transform transition-all active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
          >
            {isSubmitting ? (
              <>
                <Loader2 className="animate-spin" /> 提交中...
              </>
            ) : (
              "立即生成"
            )}
          </button>
        </div>
      </div>

      {/* Right Content - Gallery */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative">

        {/* Top Bar */}
        <div className="h-16 border-b border-slate-800 flex items-center justify-end px-8 gap-4 bg-[#020617]/80 backdrop-blur-sm z-20 absolute top-0 left-0 right-0">
          <button 
            onClick={() => window.open('https://grsai.dakka.com.cn/docs', '_blank')}
            className="text-sm text-slate-400 hover:text-white transition-colors"
          >
            使用教程
          </button>
          <button 
            onClick={() => setKeyModalOpen(true)}
            className="text-sm px-3 py-1.5 rounded bg-blue-600 hover:bg-blue-500 text-white font-medium transition-colors flex items-center gap-2"
          >
            <Settings size={14} />
            {apiKey ? 'API 已配置' : '配置 API 密钥'}
          </button>
        </div>

        {/* Gallery Grid */}
        <div className="flex-1 overflow-y-auto p-8 pt-24 custom-scrollbar">

          {tasks.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-slate-500 space-y-4">
              <div className="w-24 h-24 rounded-full bg-slate-900 flex items-center justify-center">
                <ImageIcon size={48} className="opacity-20" />
              </div>
              <p className="text-lg">生成的图片将显示在这里</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {tasks.map((task) => (
                <div key={task.id} className="group relative bg-[#0f172a] rounded-xl border border-slate-800 overflow-hidden shadow-xl transition-all hover:border-slate-600 flex flex-col aspect-square">

                  {/* Status Overlay / Image */}
                  <div className="flex-1 relative w-full h-full bg-[#1e293b]">
                    {task.status === TaskStatus.SUCCEEDED && task.resultUrl ? (
                      <>
                        <img 
                          src={task.resultUrl} 
                          alt={task.prompt} 
                          className="w-full h-full object-cover"
                          loading="lazy"
                        />
                        {/* Hover Overlay */}
                        <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4 backdrop-blur-[2px]">
                          <button 
                            onClick={() => setSelectedImage(task.resultUrl!)}
                            className="p-3 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all"
                            title="全屏查看"
                          >
                            <Maximize2 size={24} />
                          </button>
                          <button 
                            onClick={() => handleDeleteTask(task.id)}
                            className="p-3 bg-red-500/20 hover:bg-red-500/40 rounded-full text-red-400 backdrop-blur-md transition-all"
                            title="删除"
                          >
                            <Trash2 size={24} />
                          </button>
                        </div>
                      </>
                    ) : task.status === TaskStatus.FAILED ? (
                      <div className="absolute inset-0 flex flex-col items-center justify-center text-red-400 p-4 text-center">
                        <X size={32} className="mb-2" />
                        <span className="text-sm font-medium">生成失败</span>
                        <span className="text-xs text-red-400/70 mt-1 line-clamp-3">{task.error}</span>
                         <button 
                            onClick={() => handleDeleteTask(task.id)}
                            className="mt-4 p-2 text-xs bg-slate-800 rounded hover:bg-slate-700"
                          >
                            移除
                          </button>
                      </div>
                    ) : (
                      <div className="absolute inset-0 flex flex-col items-center justify-center text-blue-400">
                        <Loader2 size={32} className="animate-spin mb-3" />
                        <span className="text-sm font-medium uppercase tracking-wider">生成中...</span>
                        <div className="w-24 h-1 bg-slate-800 mt-3 rounded-full overflow-hidden">
                           <div 
                             className="h-full bg-blue-500 transition-all duration-300"
                             style={{ width: `${task.progress}%` }}
                           />
                        </div>
                      </div>
                    )}
                  </div>

                  {/* Info Footer */}
                  <div className="p-3 bg-[#0f172a] border-t border-slate-800">
                    <p className="text-xs text-slate-400 line-clamp-1" title={task.prompt}>{task.prompt}</p>
                    <div className="flex justify-between items-center mt-2">
                       <span className="text-[10px] uppercase text-slate-500 font-bold tracking-wider px-2 py-0.5 bg-slate-800 rounded">{task.model.replace('nano-banana-', '')}</span>
                       <span className="text-[10px] text-slate-600">{new Date(task.createdAt).toLocaleTimeString()}</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Modals */}
      <ApiKeyModal 
        isOpen={isKeyModalOpen} 
        onClose={() => setKeyModalOpen(false)} 
        onSave={handleSaveKey}
        existingKey={apiKey}
      />

      <CharacterLibraryModal 
        isOpen={isLibraryOpen}
        onClose={() => setLibraryOpen(false)}
        onSelect={handleSelectCharacter}
      />

      <Lightbox 
        imageUrl={selectedImage} 
        onClose={() => setSelectedImage(null)} 
      />

    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { X, Plus, Trash2, User, ImagePlus, Save, AlertCircle } from 'lucide-react';
import { Character } from '../types';
import { fileToBase64 } from '../services/api';

interface CharacterLibraryModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSelect: (character: Character) => void;
}

export const CharacterLibraryModal: React.FC<CharacterLibraryModalProps> = ({ isOpen, onClose, onSelect }) => {
  const [characters, setCharacters] = useState<Character[]>(() => {
    try {
      const saved = localStorage.getItem('grsai_character_library');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load character library", e);
      return [];
    }
  });

  const [isAdding, setIsAdding] = useState(false);
  const [newName, setNewName] = useState('');
  const [newCode, setNewCode] = useState('');
  const [newImage, setNewImage] = useState<string>('');
  const [storageError, setStorageError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      localStorage.setItem('grsai_character_library', JSON.stringify(characters));
      setStorageError(null);
    } catch (e: any) {
      console.error("Failed to save character library", e);
      if (e.name === 'QuotaExceededError' || e.message?.includes('quota')) {
        setStorageError("本地存储空间已满，新添加的角色可能无法保存。建议删除旧角色或使用较小的图片。");
      } else {
        setStorageError("保存角色库时出错。");
      }
    }
  }, [characters]);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      try {
        // Optional: Check file size here before converting
        const file = e.target.files[0];
        if (file.size > 2 * 1024 * 1024) { // 2MB warning
           // Just a warning log for now, or we could alert user
           console.warn("Image is large, might fill local storage");
        }
        const base64 = await fileToBase64(file);
        setNewImage(base64);
      } catch (err) {
        console.error(err);
      }
    }
  };

  const handleAddCharacter = () => {
    if (!newName || !newCode || !newImage) {
      alert("请填写完整信息：名称、代码和图片");
      return;
    }
    const newChar: Character = {
      id: crypto.randomUUID(),
      name: newName,
      code: newCode,
      image: newImage
    };
    setCharacters(prev => [...prev, newChar]);
    setIsAdding(false);
    setNewName('');
    setNewCode('');
    setNewImage('');
  };

  const handleDelete = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('确定要删除这个角色吗？')) {
      setCharacters(prev => prev.filter(c => c.id !== id));
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm">
      <div className="bg-[#1e293b] border border-slate-700 rounded-xl shadow-2xl w-full max-w-4xl max-h-[85vh] flex flex-col overflow-hidden">

        {/* Header */}
        <div className="p-4 border-b border-slate-700 flex justify-between items-center bg-[#0f172a]">
          <div className="flex items-center gap-2">
            <User className="text-blue-400" size={24} />
            <h2 className="text-xl font-bold text-white">角色参考库</h2>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-700 rounded-full text-slate-400 hover:text-white transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Storage Error Alert */}
        {storageError && (
          <div className="bg-red-500/10 border-b border-red-500/20 p-3 flex items-center gap-2 text-red-400 text-sm">
            <AlertCircle size={16} />
            <span>{storageError}</span>
          </div>
        )}

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 bg-[#1e293b]">

