import { Character } from '../types';
import { fileToBase64 } from '../services/api';

interface CharacterLibraryModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSelect: (character: Character) => void;
}

export const CharacterLibraryModal: React.FC<CharacterLibraryModalProps> = ({ isOpen, onClose, onSelect }) => {
  const [characters, setCharacters] = useState<Character[]>(() => {
    try {
      const saved = localStorage.getItem('grsai_character_library');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load character library", e);
      return [];
    }
  });

  const [isAdding, setIsAdding] = useState(false);
  const [newName, setNewName] = useState('');
  const [newCode, setNewCode] = useState('');
  const [newImage, setNewImage] = useState<string>('');
  const [storageError, setStorageError] = useState<string | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const importInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      localStorage.setItem('grsai_character_library', JSON.stringify(characters));
      setStorageError(null);
    } catch (e: any) {
      console.error("Failed to save character library", e);
      if (e.name === 'QuotaExceededError' || e.message?.includes('quota')) {
        setStorageError("本地存储空间已满，新添加的角色可能无法保存。建议删除旧角色或使用较小的图片。");
      } else {
        setStorageError("保存角色库时出错。");
      }
    }
  }, [characters]);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      try {
        const file = e.target.files[0];
        // 简单的大文件警告，不阻止上传，但在保存时可能会被 LocalStorage 限制拦截
        if (file.size > 2 * 1024 * 1024) { 
           console.warn("Image is large, might fill local storage");
        }
        const base64 = await fileToBase64(file);
        setNewImage(base64);
      } catch (err) {
        console.error(err);
      }
    }
  };

  const handleAddCharacter = () => {
    if (!newName || !newCode || !newImage) {
      alert("请填写完整信息：名称、代码和图片");
      return;
    }
    const newChar: Character = {
      id: crypto.randomUUID(),
      name: newName,
      code: newCode,
      image: newImage
    };
    setCharacters(prev => [...prev, newChar]);
    setIsAdding(false);
    setNewName('');
    setNewCode('');
    setNewImage('');
  };

  const handleDelete = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('确定要删除这个角色吗？')) {
      setCharacters(prev => prev.filter(c => c.id !== id));
    }
  };

  // --- Export Logic ---
  const handleExport = () => {
    if (characters.length === 0) {
      alert("没有可导出的角色");
      return;
    }
    const dataStr = JSON.stringify(characters, null, 2);
    const blob = new Blob([dataStr], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `nano_banana_characters_${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  // --- Import Logic ---
  const handleImportClick = () => {
    importInputRef.current?.click();
  };

  const handleImportFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        if (Array.isArray(json)) {
          // Validate and sanitize imported data
          const validChars: Character[] = json
            .filter((c: any) => c.name && c.code && c.image)
            .map((c: any) => ({
              id: crypto.randomUUID(), // Generate new IDs to avoid collisions
              name: c.name,
              code: c.code,
              image: c.image
            }));

          if (validChars.length === 0) {
            alert("文件中未发现有效的角色数据。");
            return;
          }

          if (confirm(`发现 ${validChars.length} 个有效角色。是否导入？(将追加到现有列表)`)) {
            setCharacters(prev => [...prev, ...validChars]);
          }
        } else {
          alert("文件格式不正确，应为角色数组。");
        }
      } catch (err) {
        console.error(err);
        alert("无法解析 JSON 文件。");
      }
    };
    reader.readAsText(file);
    // Reset input
    e.target.value = '';
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm">
      <div className="bg-[#1e293b] border border-slate-700 rounded-xl shadow-2xl w-full max-w-4xl max-h-[85vh] flex flex-col overflow-hidden">

        {/* Header */}
        <div className="p-4 border-b border-slate-700 flex justify-between items-center bg-[#0f172a]">
          <div className="flex items-center gap-2">
            <User className="text-blue-400" size={24} />
            <h2 className="text-xl font-bold text-white">角色参考库</h2>
          </div>

          <div className="flex items-center gap-2">
            {/* Hidden Import Input */}
            <input 
              type="file" 
              accept=".json" 
              ref={importInputRef} 
              className="hidden" 
              onChange={handleImportFile}
            />

            <button 
              onClick={handleImportClick}
              className="p-2 text-slate-400 hover:text-white hover:bg-slate-700 rounded-lg transition-colors flex items-center gap-1.5 text-xs font-medium"
              title="导入 JSON"
            >
              <Upload size={16} />
              <span className="hidden sm:inline">导入</span>
            </button>

            <button 
              onClick={handleExport}
              className="p-2 text-slate-400 hover:text-white hover:bg-slate-700 rounded-lg transition-colors flex items-center gap-1.5 text-xs font-medium"
              title="导出 JSON"
            >
              <Download size={16} />
              <span className="hidden sm:inline">导出</span>
            </button>

            <div className="w-px h-6 bg-slate-700 mx-1"></div>

            <button onClick={onClose} className="p-2 hover:bg-slate-700 rounded-full text-slate-400 hover:text-white transition-colors">
              <X size={24} />
            </button>
          </div>
        </div>

        {/* Storage Error Alert */}
        {storageError && (
          <div className="bg-red-500/10 border-b border-red-500/20 p-3 flex items-center gap-2 text-red-400 text-sm animate-in fade-in slide-in-from-top-2">
            <AlertCircle size={16} />
            <span>{storageError}</span>
          </div>
        )}

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 bg-[#1e293b]">

          {/* Add Form or Button */}
          {isAdding ? (
            <div className="mb-6 p-4 bg-[#0f172a] rounded-lg border border-slate-600 animate-in fade-in slide-in-from-top-4">
               <h3 className="text-sm font-bold text-slate-300 mb-4 uppercase tracking-wider">添加新角色</h3>
               <div className="flex gap-4 items-start">
                  <div 
